INSERT OR REPLACE INTO reels (equipmentName, equipmentType, category, subCategory, model, description, transmissionRatio, transmissionRatioStar, enginePower, lineSpeed, lineSpeedStar, size, form, frictionForce, frictionForceStar, windingSpeed, test, testStar, levelReq, spoolCapacity, obtainMethod, rating, adaptWeight, adaptWeightStar, goldPrice, silverPrice, lockTension, lockTensionStar, saltwaterResistant) VALUES ('Full Metal 60', '渔轮', '新年系列 纺车式', 'Full Metal 60', 'Full Metal 60', 'Full Metal 60 是Trident公司提供的精美复古鱼线轮。 尽管年代久远，它不仅吸引了收藏家的兴趣，而且仍然可以成功地使用钓鱼。 Full Metal 60属于动力纺车轮的类型，由于其设计，能够承受很大的负载。', '4.5:1', '', '', '0.69', '', '6000', '纺车式', '18.2kg', '', '', '8g', '', '24', '', '', '', '', '', '42.09', '5498.8', '49.15kg', 0, '💧');
INSERT OR REPLACE INTO reels (equipmentName, equipmentType, category, subCategory, model, description, transmissionRatio, transmissionRatioStar, enginePower, lineSpeed, lineSpeedStar, size, form, frictionForce, frictionForceStar, windingSpeed, test, testStar, levelReq, spoolCapacity, obtainMethod, rating, adaptWeight, adaptWeightStar, goldPrice, silverPrice, lockTension, lockTensionStar, saltwaterResistant) VALUES ('Model De Luxe', '渔轮', '新年系列 纺车式', 'Model De Luxe', 'Model De Luxe 430S', '尽管Model De Luxe 430S是50多年前开发的，但它可以成功地使用钓鱼(纺车竿和底部)。 Model De Luxe 430S具有简单可靠的设计，可以承受重负载。', '3.8:1', '', '', '0.44', '', '4000', '纺车式', '9kg', '', '', '4g', '', '14', '', '', '', '', '', '6.90', '789.80', '24.24kg', 0, '~');
INSERT OR REPLACE INTO reels (equipmentName, equipmentType, category, subCategory, model, description, transmissionRatio, transmissionRatioStar, enginePower, lineSpeed, lineSpeedStar, size, form, frictionForce, frictionForceStar, windingSpeed, test, testStar, levelReq, spoolCapacity, obtainMethod, rating, adaptWeight, adaptWeightStar, goldPrice, silverPrice, lockTension, lockTensionStar, saltwaterResistant) VALUES ('Overlord 88', '渔轮', '新年系列 纺车式', 'Overlord 88', 'Overlord 88', 'Overlord 系列鱼线轮 Zeiman的生产时间不长，今天，找到这种型号非常成功。 但是除了它们的稀有性之外，Overlord 鱼线轮还具有出色的性能。 它们的机制非常可靠。 它们可以让您进行长距离抛掷，甚至可以处理非常大的鱼。', '4.5:1', '', '', '1.05', '', '8000', '纺车式', '24.5kg', '', '', '12g', '', '27', '', '', '', '', '', '103.22', '17889.25', '81.46kg', 0, '');
