INSERT OR REPLACE INTO reels (equipmentName, equipmentType, category, subCategory, model, description, transmissionRatio, transmissionRatioStar, enginePower, lineSpeed, lineSpeedStar, size, form, frictionForce, frictionForceStar, windingSpeed, test, testStar, levelReq, spoolCapacity, obtainMethod, rating, adaptWeight, adaptWeightStar, goldPrice, silverPrice, lockTension, lockTensionStar, saltwaterResistant) VALUES ('Zero 2 Z', '渔轮', '水滴轮', 'Zero 2 Z', 'Zero 2 Z-R', 'Zero 2 Z – 是Zeiman公司制造的专业水滴轮更新系列。 复合材料和铝的广泛使用已积极影响了鱼线轮的重量。 轻的带孔线轴和减小的摩擦系数的轴承使您可以放心地使用小型、轻量的拟饵。 Zero 2系列包括具有不同齿轮比的线轮。', '6.4:1', '', '', '0.62', '', 'LP', '水滴轮', '7.7kg', '', '', '≥3.7g', '', '20', '', '', '', '', '', '28.37', '3489.5', '44.59kg', 0, '-');
INSERT OR REPLACE INTO reels (equipmentName, equipmentType, category, subCategory, model, description, transmissionRatio, transmissionRatioStar, enginePower, lineSpeed, lineSpeedStar, size, form, frictionForce, frictionForceStar, windingSpeed, test, testStar, levelReq, spoolCapacity, obtainMethod, rating, adaptWeight, adaptWeightStar, goldPrice, silverPrice, lockTension, lockTensionStar, saltwaterResistant) VALUES ('Zero GS ZG-R', '渔轮', '水滴轮', 'Zero GS ZG-R', 'Zero GS ZG-R', 'Zero GS – Zeiman公司制造的水滴轮系列。Zero鱼线轮加强版。作为改进的结果，Zero GS显着提高了动力和抗冲击负荷。鱼线轮具有对于该级别非常强大的摩擦制动。', '7.1:1', '', '', '0.67', '', 'LP', '水滴轮', '9kg', '', '', '≥1.7g', '', '22', '', '', '', '', '', '34.61', '4377.1', '56.56kg', 0, '-');
INSERT OR REPLACE INTO reels (equipmentName, equipmentType, category, subCategory, model, description, transmissionRatio, transmissionRatioStar, enginePower, lineSpeed, lineSpeedStar, size, form, frictionForce, frictionForceStar, windingSpeed, test, testStar, levelReq, spoolCapacity, obtainMethod, rating, adaptWeight, adaptWeightStar, goldPrice, silverPrice, lockTension, lockTensionStar, saltwaterResistant) VALUES ('奥拉夫HS-LP', '渔轮', '水滴轮', '奥拉夫HS-LP', 'Olaf HS-LP', '低调的奥拉夫 HS LP 被定位为一款通用型号，既适合专业竞技钓鱼，也方便周末休闲垂钓。尺寸小巧却性能不俗，坚固的石墨框架带来出色的结构刚度，也最大限度地降低渔线轮的重量。专有的 CS Ultra 泄力系统可提供顺滑且强劲的曳力表现，而磁力制动系统则可确保在使用各种路亚时实现精准抛投，使奥拉夫 HS LP 成为适用于所有形式作钓的可靠渔线轮。', '', '7.1:1', '', '0.79', '', 'LP', '水滴轮', '8.6kg', '', '', '≥2.9g', '', '25', '', '', '', '', '', '47.80', '6398.6', '34.65kg', 0, '-');
INSERT OR REPLACE INTO reels (equipmentName, equipmentType, category, subCategory, model, description, transmissionRatio, transmissionRatioStar, enginePower, lineSpeed, lineSpeedStar, size, form, frictionForce, frictionForceStar, windingSpeed, test, testStar, levelReq, spoolCapacity, obtainMethod, rating, adaptWeight, adaptWeightStar, goldPrice, silverPrice, lockTension, lockTensionStar, saltwaterResistant) VALUES ('岩浆XHS-LP', '渔轮', '水滴轮', '岩浆XHS-LP', 'Magma XHS-LP', '泽曼渔具公司（Zeiman ）推出的系列新款水滴轮，结合现代设计与尖端工程学，机身采用特殊的耐腐蚀合金，侧板则由碳纤维制成。超轻铝制线轴具有完美的平衡性，CS Ultra 摩擦制动系统确保顺滑且可控的出线，而高精度磁力摩擦刹车则允许精准调节刹车力。这确保了最大程度的顺滑性和远距离抛投的精确度。', '', '8.1:1', '', '0.86', '', 'LP', '水滴轮', '8.9kg', '', '', '≥2.5g', '', '25', '', '', '', '', '', '60.77', '8599.6', '32kg', 0, '-');
INSERT OR REPLACE INTO reels (equipmentName, equipmentType, category, subCategory, model, description, transmissionRatio, transmissionRatioStar, enginePower, lineSpeed, lineSpeedStar, size, form, frictionForce, frictionForceStar, windingSpeed, test, testStar, levelReq, spoolCapacity, obtainMethod, rating, adaptWeight, adaptWeightStar, goldPrice, silverPrice, lockTension, lockTensionStar, saltwaterResistant) VALUES ('岩浆XHS-LP 九周年纪念版', '渔轮', '水滴轮', '岩浆XHS-LP 九周年纪念版', 'Magma XHS-LP 9-Years', '岩浆XHS-LP水滴轮的九周年纪念版。工程师不仅开发了独特的外观设计，还为其配备了高可靠性的结构，具有更高的传动比和加强型摩擦制动系统。', '', '8.3:1', '', '0.88', '', 'LP', '水滴轮', '9kg', '', '', '≥2.5g', '', '25', '', '', '', '', '', '60.77', 0, '35kg', 0, '-');
