INSERT OR REPLACE INTO reels (equipmentName, equipmentType, category, subCategory, model, description, transmissionRatio, transmissionRatioStar, enginePower, lineSpeed, lineSpeedStar, size, form, frictionForce, frictionForceStar, windingSpeed, test, testStar, levelReq, spoolCapacity, obtainMethod, rating, adaptWeight, adaptWeightStar, goldPrice, silverPrice, lockTension, lockTensionStar, saltwaterResistant) VALUES ('Black Box', '渔轮', '鼓轮', 'Black Box', 'Black Box ZBB50', 'Black Box – 多年来深受欢迎的通用倍增经济型经典系列。强大而坚固的鱼线轮体现了Zeiman的传奇品质。该系列鱼线轮的基础是一个钢架，机构配备了旋制青铜齿轮。适用于任何重量级的绞钓。用于拖钓及其它钓鱼爱好者的，具有鱼线计数器的鱼线轮系列。', '', '5.9:1', '', '0.62', '', '5000', '鼓轮', '9kg', '', '', '', '', '16', '', '', '', '', '≥11.5g', '10.34', '1159.8', '37.14kg', 0, '');
