INSERT OR REPLACE INTO reels (equipmentName, equipmentType, category, subCategory, model, description, transmissionRatio, transmissionRatioStar, enginePower, lineSpeed, lineSpeedStar, size, form, frictionForce, frictionForceStar, windingSpeed, test, testStar, levelReq, spoolCapacity, obtainMethod, rating, adaptWeight, adaptWeightStar, goldPrice, silverPrice, lockTension, lockTensionStar, saltwaterResistant) VALUES ('Centauri', '渔轮', '鼓轮', 'Centauri', 'Centauri ZC70', 'Centauri – 为拖钓设计的鼓轮（“动力”鱼线轮）系列。在倍增鱼线轮中拖钓鱼线轮占据特殊位置。他们大而强，能够用沉重的拟饵工作，并能够遏制最大的水下掠食者。Centauri系列也不例外。这种鱼线轮的可靠性高，运行平稳，并且由于其优异的耐水性，它们可用于海上捕捞。在系列有些型号中，配有鱼线计数器。', '4.7:1', '', '', '0.57', '', '7000', '鼓轮', '', '20.4kg', '', '', '', '27', '', '', '', '', '≥27.5g', '95.99', '15998.5', '117.4kg', 0, '💧');
